            if (path[i] !== path[m - 1 - i]) {
                isPalindrome = false;
                break;
            }
        }
        if (isPalindrome) {
            maxLen = Math.max(maxLen, m);
        }
        for (const neighbor of adj[node]) {
            if ((bitmask & (1 << neighbor)) === 0) {
                const newBitmask = bitmask | (1 << neighbor);
                const newPath = [...path, label[neighbor]];
                dfs(neighbor, newBitmask, newPath);
            }
        }
    }

    for (let i = 0; i < n; i++) {
        const path = [label[i]];
        dfs(i, 1 << i, path);
    }

    return maxLen;
}
